from functools import lru_cache

def isScramble(s1: str, s2: str) -> bool:
    if s1 == s2:
        return True
    if len(s1) != len(s2):
        return False

    @lru_cache(maxsize=None)
    def dp(a: str, b: str) -> bool:
        if a == b:
            return True
        if sorted(a) != sorted(b):  # quick prune
            return False
        n = len(a)
        for k in range(1, n):
            # No swap
            if dp(a[:k], b[:k]) and dp(a[k:], b[k:]):
                return True
            # Swap
            if dp(a[:k], b[n - k:]) and dp(a[k:], b[:n - k]):
                return True
        return False

    return dp(s1, s2)
